import React from 'react';
import { useCurrentFrame, useVideoConfig, interpolate, spring } from 'remotion';
import { z } from 'zod';
import { SPRING_SMOOTH } from '../../../lib/motion';
import { HOUSE_EASE } from '../../../lib/easing';
import { sizeRoleSchema, resolveSize } from '../../../lib/canvas';

/** Zod schema for {@link WordRotate} props — drives Remotion `defaultProps` validation. */
export const wordRotateSchema = z.object({
  /** Phrases cycled in place, in order. One is visible at a time. */
  phrases: z.array(z.string()).default(['fast', 'beautiful', 'restrained']),
  /** Frames before the first phrase begins to enter. */
  delay: z.number().int().min(0).default(0),
  /** Frames each phrase holds at full opacity before the next arrives. */
  holdDuration: z.number().int().min(1).default(30),
  /** Frames for a single phrase to fade in (and, separately, fade out). */
  transitionDuration: z.number().int().min(1).default(12),
  /** Text color. Defaults to `--onda-text` (`#F2F2F4`). */
  color: z.string().default('#F2F2F4'),
  /** Pixels. Wins over `size` if both are passed. */
  fontSize: z.number().default(96),
  /** Semantic typography role — resolves to canvas-aware pixels via the smaller canvas dimension. Overrides `fontSize`'s default when passed alone; `fontSize` wins when both are passed. */
  size: sizeRoleSchema.optional(),
  /** Onda display font. Never default to Inter / Arial / system. */
  fontFamily: z.string().default('"Clash Display", sans-serif'),
});

/** Inferred props for {@link WordRotate}. */
export type WordRotateProps = z.infer<typeof wordRotateSchema>;

/**
 * Cycles through phrases in place. Each phrase rises in on `SPRING_SMOOTH`,
 * holds at full opacity, then fades down as the next arrives. One focal
 * element per moment — phrases are stacked at the same center point but only
 * one is visible at a time.
 *
 * @example
 * <WordRotate phrases={['fast', 'beautiful', 'restrained']} />
 */
export const WordRotate: React.FC<WordRotateProps> = ({
  phrases,
  delay,
  holdDuration,
  transitionDuration,
  color,
  fontSize,
  size,
  fontFamily,
}) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const resolvedFontSize = size ? resolveSize(size, { width, height }) : fontSize;

  // Each phrase owns a window of (transitionDuration + holdDuration) frames.
  // Inside its window: fade-in over `transitionDuration`, hold for
  // `holdDuration`, fade-out over `transitionDuration` (overlapping the next
  // phrase's fade-in — they share the slot, so the swap reads as one motion).
  const slot = holdDuration + transitionDuration;

  return (
    <div style={{ position: 'relative', display: 'inline-block' }}>
      {phrases.map((phrase, i) => {
        const phraseStart = delay + i * slot;
        const local = frame - phraseStart;

        // Rise on SPRING_SMOOTH — Onda's house spring, no overshoot.
        const rise = spring({
          frame: local,
          fps,
          config: SPRING_SMOOTH,
          durationInFrames: transitionDuration,
        });
        const translateY = interpolate(rise, [0, 1], [12, 0], {
          extrapolateLeft: 'clamp',
          extrapolateRight: 'clamp',
        });

        // Opacity: 0 → 1 over transitionDuration, hold at 1 for holdDuration,
        // 1 → 0 over the next transitionDuration. HOUSE_EASE per CLAUDE.md §3.
        const opacity = interpolate(
          local,
          [0, transitionDuration, transitionDuration + holdDuration, slot + transitionDuration],
          [0, 1, 1, 0],
          {
            extrapolateLeft: 'clamp',
            extrapolateRight: 'clamp',
            easing: HOUSE_EASE,
          },
        );

        return (
          <div
            key={i}
            style={{
              position: i === 0 ? 'relative' : 'absolute',
              top: 0,
              left: 0,
              opacity,
              transform: `translateY(${translateY}px)`,
              color,
              fontSize: resolvedFontSize,
              fontFamily,
              fontWeight: 600,
              letterSpacing: '-0.02em',
              whiteSpace: 'nowrap',
            }}
          >
            {phrase}
          </div>
        );
      })}
    </div>
  );
};

export default WordRotate;

// Re-exports the Zod schema so tooling (registry builds, docs site,
// training-data pipelines) can consume props validation without pulling
// in the component itself.
export { wordRotateSchema, type WordRotateProps } from './WordRotate';

# WordRotate

Cycles through a list of phrases in place. Each phrase rises 12px and fades in on `SPRING_SMOOTH`, holds at full opacity, then fades out as the next arrives. Phrases are stacked at the same center point so only one is visible at a time — one focal element per moment, the Onda way.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `phrases` | `string[]` | `['fast', 'beautiful', 'restrained']` | Phrases shown in order, one at a time. |
| `delay` | `integer ≥ 0` | `0` | Frames before the first phrase begins to enter. |
| `holdDuration` | `integer ≥ 1` | `30` | Frames each phrase holds at full opacity. |
| `transitionDuration` | `integer ≥ 1` | `12` | Frames to fade a phrase in (and, separately, out). |
| `color` | `string` | `"#F2F2F4"` | Text color — defaults to `--onda-text`. |
| `fontSize` | `number` | `96` | Pixels. Wins over `size` if both are passed. |
| `size` | `SizeRole?` | – | Semantic typography role — `'hero'` \| `'heading'` \| `'subheading'` \| `'body'` \| `'caption'`. Resolves to canvas-aware pixels via the smaller canvas dimension. `fontSize` wins when both are passed. |
| `fontFamily` | `string` | `'"Clash Display", sans-serif'` | The Onda display font. Never default to Inter / Arial / system. |

## Usage

```tsx
import { Composition } from 'remotion';
import { WordRotate, wordRotateSchema } from './components/onda/word-rotate/WordRotate';

export const Root: React.FC = () => (
  <Composition
    id="WordRotate"
    component={WordRotate}
    durationInFrames={150}
    fps={30}
    width={1080}
    height={1920}
    schema={wordRotateSchema}
    defaultProps={{
      phrases: ['fast', 'beautiful', 'restrained'],
      delay: 0,
      holdDuration: 30,
      transitionDuration: 12,
      color: '#F2F2F4',
      fontSize: 96,
      fontFamily: '"Clash Display", sans-serif',
    }}
  />
);
```

## Motion notes

- Each phrase occupies a slot of `transitionDuration + holdDuration` frames. Inside the slot it fades in over `transitionDuration`, holds at 1 for `holdDuration`, then fades out over the next `transitionDuration` — overlapping the incoming phrase's fade-in so the swap reads as one motion.
- Rise is driven by `SPRING_SMOOTH` from `lib/motion.ts` (the Onda house default, no overshoot). 12px travel — small on purpose.
- Opacity uses `HOUSE_EASE` from `lib/easing.ts` per CLAUDE.md §3.
- All phrases after the first are absolutely positioned at the same center point so they stack visually — only one is visible at a time.
- All `interpolate` calls clamp at both ends — the component is correct on frame 0 and on any frame past the last phrase's window.
